const mailgun = new dr((form_data_default()));
const optionalFields = ['cc', 'text', 'html'];

function loadConfig() {
  return {
    apiKey: getInput('api-key'),
    domain: getInput('domain'),
    to: getInput('to'),
    from: getInput('from'),
    cc: getInput('cc'),
    subject: getInput('subject'),
    text: getInput('text'),
    html: getInput('html'),
  }
}

function validate(config) {
  for (const param in config) {
    if (optionalFields.includes(param)) {
      continue;
    }
    validateRequiredParameter(config[param], `'${param}'`);
  }
}

function validateRequiredParameter(value, name) {
  if (!isNonEmptyString(value)) {
    throw new Error(`${name} must be a non-empty string.`);
  }
}

function sendEmail(config) {
  const mg = mailgun.client({
    username: 'api',
    key: config.apiKey,
  });

  return mg.messages
    .create(config.domain, {
      from: config.from,
      to: config.to,
      cc: config.cc,
      subject: config.subject,
      text: config.text,
      html: config.html,
    })
    .then((resp) => {
      setOutput('response', resp.message);
      return;
    })
    .catch((err) => {
      setFailed(err.message);
    });
}

function isNonEmptyString(value) {
  return typeof value === 'string' && value !== '';
}

const config = loadConfig();
validate(config);
sendEmail(config);

